import 'dart:async'; import 'package:flutter/material.dart'; import '../../../core/theme/app_theme.dart'; class CallTimer extends StatefulWidget { final DateTime startTime; const CallTimer({super.key, required this.startTime}); @override State<CallTimer> createState() => _CallTimerState(); } class _CallTimerState extends State<CallTimer> { late Timer _timer; Duration _elapsed = Duration.zero; @override void initState() { super.initState(); _timer = Timer.periodic(const Duration(seconds: 1), (_) => setState(() => _elapsed = DateTime.now().difference(widget.startTime))); } @override void dispose() { _timer.cancel(); super.dispose(); } @override Widget build(BuildContext context) { final m = _elapsed.inMinutes.toString().padLeft(2,'0'); final s = (_elapsed.inSeconds%60).toString().padLeft(2,'0'); return Text('${_elapsed.inHours > 0 ? '${_elapsed.inHours.toString().padLeft(2,"0")}:' : ''}$m:$s', style: const TextStyle(color: AppTheme.successColor, fontSize: 18, fontWeight: FontWeight.w600, fontFeatures: [FontFeature.tabularFigures()])); } }